import React, { useState, useEffect, useRef } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import {
  Box, Drawer, AppBar, Toolbar, List, Typography, Divider, IconButton,
  ListItem, ListItemButton, ListItemIcon, ListItemText, useMediaQuery
} from '@mui/material';
import {
  Menu as MenuIcon, Dashboard as DashboardIcon, Business as BusinessIcon,
  AttachMoney as MoneyIcon, Psychology as MindsetIcon, School as SchoolIcon,
  FitnessCenter as HealthIcon, CheckCircle as CheckIcon,
  Assessment as ReportsIcon, SmartToy as AIIcon, Logout as LogoutIcon,
  EmojiEvents as TrophyIcon
} from '@mui/icons-material';
import { useAuth } from '../context/AuthContext';

const drawerWidth = 250;

// Greenery + Pearl color palette
const C = {
  green: '#478559',
  greenDark: '#2d5c3d',
  greenLight: '#5a9e70',
  purple: '#161748',
  purpleMid: '#232460',
  greyBlue: '#4f5f76',
  pearl: '#f5f0e8',
  pearlDark: '#ede5d8',
  cream: '#faf7f2',
  white: '#ffffff',
  textDark: '#1a1a2e',
  textMid: '#4f5f76',
  textLight: '#7a8a9a',
};

const menuItems = [
  { text: 'Dashboard', icon: <DashboardIcon />, path: '/' },
  { text: 'Business', icon: <BusinessIcon />, path: '/business' },
  { text: 'Best Idea', icon: <TrophyIcon />, path: '/best-idea' },
  { text: 'Financial', icon: <MoneyIcon />, path: '/financial' },
  { text: 'Mindset', icon: <MindsetIcon />, path: '/mindset' },
  { text: 'Learning', icon: <SchoolIcon />, path: '/learning' },
  { text: 'Health', icon: <HealthIcon />, path: '/health' },
  { text: 'Check-in', icon: <CheckIcon />, path: '/checkin' },
  { text: 'Reports', icon: <ReportsIcon />, path: '/reports' },
  { text: 'AI Advisor', icon: <AIIcon />, path: '/ai' },
];

// Cursor glow component
function CursorGlow() {
  const glowRef = useRef(null);
  const pos = useRef({ x: 0, y: 0 });
  const current = useRef({ x: 0, y: 0 });

  useEffect(() => {
    const onMove = (e) => { pos.current = { x: e.clientX, y: e.clientY }; };
    window.addEventListener('mousemove', onMove);
    let raf;
    const animate = () => {
      current.current.x += (pos.current.x - current.current.x) * 0.1;
      current.current.y += (pos.current.y - current.current.y) * 0.1;
      if (glowRef.current) {
        glowRef.current.style.left = current.current.x + 'px';
        glowRef.current.style.top = current.current.y + 'px';
      }
      raf = requestAnimationFrame(animate);
    };
    raf = requestAnimationFrame(animate);
    return () => { window.removeEventListener('mousemove', onMove); cancelAnimationFrame(raf); };
  }, []);

  return (
    <Box ref={glowRef} sx={{
      position: 'fixed', pointerEvents: 'none', zIndex: 9999,
      width: 400, height: 400,
      borderRadius: '50%',
      background: `radial-gradient(circle, rgba(71,133,89,0.12) 0%, rgba(22,23,72,0.04) 50%, transparent 70%)`,
      transform: 'translate(-50%, -50%)',
      transition: 'none',
    }} />
  );
}

// Tilt card wrapper
function TiltCard({ children, sx }) {
  const ref = useRef(null);
  const handleMove = (e) => {
    if (!ref.current) return;
    const rect = ref.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width - 0.5;
    const y = (e.clientY - rect.top) / rect.height - 0.5;
    ref.current.style.transform = `perspective(800px) rotateY(${x * 6}deg) rotateX(${-y * 6}deg) scale(1.02)`;
  };
  const handleLeave = () => {
    if (ref.current) ref.current.style.transform = 'perspective(800px) rotateY(0deg) rotateX(0deg) scale(1)';
  };
  return (
    <Box ref={ref} onMouseMove={handleMove} onMouseLeave={handleLeave}
      sx={{ transition: 'transform 0.15s ease', ...sx }}>
      {children}
    </Box>
  );
}

// Logo component - SW PG
function Logo({ size = 40 }) {
  return (
    <Box sx={{
      width: size, height: size, borderRadius: '10px',
      background: `linear-gradient(135deg, ${C.green} 0%, ${C.greenDark} 100%)`,
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      boxShadow: `0 4px 15px rgba(71,133,89,0.4)`,
      position: 'relative', overflow: 'hidden',
      '&::before': {
        content: '""', position: 'absolute', inset: 0,
        background: `linear-gradient(135deg, rgba(255,255,255,0.15) 0%, transparent 60%)`,
      }
    }}>
      <Typography sx={{
        fontSize: size * 0.28, fontWeight: 900, color: C.pearl,
        letterSpacing: '-0.5px', lineHeight: 1, fontFamily: '"Georgia", serif',
        textShadow: '0 1px 3px rgba(0,0,0,0.3)'
      }}>
        SW
      </Typography>
    </Box>
  );
}

export { TiltCard, Logo, C };

export default function Layout() {
  const [mobileOpen, setMobileOpen] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();
  const { user, logout } = useAuth();
  const isMobile = useMediaQuery('(max-width:600px)');

  const handleLogout = () => { logout(); navigate('/'); };

  const drawer = (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column',
      background: `linear-gradient(180deg, ${C.purple} 0%, ${C.purpleMid} 60%, ${C.greyBlue} 100%)` }}>

      {/* Logo + Brand */}
      <Box sx={{ p: 3, display: 'flex', alignItems: 'center', gap: 1.5 }}>
        <Logo size={42} />
        <Box>
          <Typography sx={{ fontWeight: 800, fontSize: '1.1rem', color: C.pearl, letterSpacing: '-0.3px', lineHeight: 1 }}>
            SW PG
          </Typography>
          <Typography sx={{ fontSize: '0.65rem', color: 'rgba(245,240,232,0.5)', letterSpacing: 2, textTransform: 'uppercase' }}>
            Personal OS
          </Typography>
        </Box>
      </Box>

      <Divider sx={{ borderColor: 'rgba(245,240,232,0.1)', mx: 2 }} />

      {/* Nav items */}
      <List sx={{ px: 1.5, pt: 1.5, flex: 1 }}>
        {menuItems.map((item) => {
          const isActive = location.pathname === item.path ||
            (item.path !== '/' && location.pathname.startsWith(item.path));
          return (
            <ListItem key={item.text} disablePadding sx={{ mb: 0.5 }}>
              <ListItemButton
                onClick={() => { navigate(item.path); if (isMobile) setMobileOpen(false); }}
                sx={{
                  borderRadius: 2, px: 2, py: 1,
                  bgcolor: isActive ? `rgba(71,133,89,0.25)` : 'transparent',
                  border: `1px solid ${isActive ? 'rgba(71,133,89,0.5)' : 'transparent'}`,
                  '&:hover': {
                    bgcolor: `rgba(71,133,89,0.15)`,
                    border: `1px solid rgba(71,133,89,0.3)`,
                    transform: 'translateX(4px)',
                  },
                  transition: 'all 0.2s ease',
                }}
              >
                <ListItemIcon sx={{ minWidth: 36, color: isActive ? C.greenLight : 'rgba(245,240,232,0.5)' }}>
                  {item.icon}
                </ListItemIcon>
                <ListItemText primary={item.text} primaryTypographyProps={{
                  fontWeight: isActive ? 700 : 500,
                  color: isActive ? C.pearl : 'rgba(245,240,232,0.65)',
                  fontSize: '0.875rem',
                }} />
                {isActive && (
                  <Box sx={{ width: 4, height: 20, borderRadius: 2, bgcolor: C.green, ml: 1 }} />
                )}
              </ListItemButton>
            </ListItem>
          );
        })}
      </List>

      <Divider sx={{ borderColor: 'rgba(245,240,232,0.1)', mx: 2 }} />

      {/* User + logout */}
      <Box sx={{ p: 2 }}>
        <ListItemButton onClick={handleLogout} sx={{
          borderRadius: 2, px: 2, py: 1,
          '&:hover': { bgcolor: 'rgba(255,100,100,0.15)' }, transition: 'all 0.2s'
        }}>
          <ListItemIcon sx={{ minWidth: 36, color: 'rgba(245,240,232,0.4)' }}>
            <LogoutIcon fontSize="small" />
          </ListItemIcon>
          <ListItemText primary="Logout" primaryTypographyProps={{ color: 'rgba(245,240,232,0.4)', fontSize: '0.85rem' }} />
        </ListItemButton>
      </Box>
    </Box>
  );

  return (
    <Box sx={{ display: 'flex', bgcolor: C.cream, minHeight: '100vh' }}>
      <CursorGlow />

      {/* AppBar */}
      <AppBar position="fixed" elevation={0} sx={{
        zIndex: (theme) => theme.zIndex.drawer + 1,
        bgcolor: 'rgba(250,247,242,0.92)',
        backdropFilter: 'blur(12px)',
        borderBottom: `1px solid rgba(71,133,89,0.15)`,
      }}>
        <Toolbar sx={{ gap: 2 }}>
          <IconButton edge="start" onClick={() => setMobileOpen(!mobileOpen)}
            sx={{ display: { sm: 'none' }, color: C.purple }}>
            <MenuIcon />
          </IconButton>

          {/* Logo in topbar on mobile */}
          <Box sx={{ display: { sm: 'none' }, alignItems: 'center', gap: 1.5 }}>
            <Logo size={32} />
          </Box>

          <Typography variant="h6" sx={{
            flexGrow: 1, fontWeight: 700, color: C.purple,
            fontSize: '1rem', letterSpacing: '-0.3px'
          }}>
            {menuItems.find(m => m.path === location.pathname)?.text || 'Dashboard'}
          </Typography>

          {/* User pill */}
          <Box sx={{
            px: 2, py: 0.5, borderRadius: 10,
            bgcolor: `rgba(71,133,89,0.1)`,
            border: `1px solid rgba(71,133,89,0.2)`,
            display: 'flex', alignItems: 'center', gap: 1
          }}>
            <Box sx={{ width: 8, height: 8, borderRadius: '50%', bgcolor: C.green }} />
            <Typography variant="caption" sx={{ color: C.green, fontWeight: 700 }}>
              {user?.username || 'Sirawdink'}
            </Typography>
          </Box>
        </Toolbar>
      </AppBar>

      {/* Sidebar */}
      <Box component="nav" sx={{ width: { sm: drawerWidth }, flexShrink: { sm: 0 } }}>
        <Drawer
          variant={isMobile ? 'temporary' : 'permanent'}
          open={isMobile ? mobileOpen : true}
          onClose={() => setMobileOpen(false)}
          ModalProps={{ keepMounted: true }}
          sx={{
            '& .MuiDrawer-paper': {
              width: drawerWidth, boxSizing: 'border-box',
              border: 'none',
              boxShadow: `4px 0 24px rgba(22,23,72,0.15)`,
            },
          }}
        >
          {drawer}
        </Drawer>
      </Box>

      {/* Main content */}
      <Box component="main" sx={{
        flexGrow: 1,
        width: { sm: `calc(100% - ${drawerWidth}px)` },
        bgcolor: C.cream, minHeight: '100vh',
      }}>
        <Toolbar />
        <Box sx={{ p: { xs: 2, sm: 3 } }}>
          <Outlet />
        </Box>
      </Box>
    </Box>
  );
}
